{
  "name": "Lumina 4K Upscaler",
  "description": "Professional-grade image upscaling tool using Gemini 3 Pro to transform images into 4K resolution with extreme detail retention."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppStatus {
  IDLE = 'IDLE',
  SELECTING_IMAGE = 'SELECTING_IMAGE',
  READY_TO_UPSCALE = 'READY_TO_UPSCALE',
  PROCESSING = 'PROCESSING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

export interface ImageData {
  url: string;
  base64: string;
  mimeType: string;
  width?: number;
  height?: number;
}

export interface ProcessingStats {
  durationMs: number;
  originalSize: string;
}

import { GoogleGenAI } from "@google/genai";

// Declaration for the AI Studio global object
declare global {
  interface Window {
    aistudio?: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

export const checkApiKey = async (): Promise<boolean> => {
  if (window.aistudio && window.aistudio.hasSelectedApiKey) {
    return await window.aistudio.hasSelectedApiKey();
  }
  return false;
};

export const promptForApiKey = async (): Promise<void> => {
  if (window.aistudio && window.aistudio.openSelectKey) {
    await window.aistudio.openSelectKey();
  } else {
    console.error("AI Studio environment not detected.");
    throw new Error("AI Studio environment not supported. Please run this app in the Project IDX or AI Studio environment.");
  }
};

export const upscaleImage = async (
  base64Data: string,
  mimeType: string
): Promise<string> => {
  // Always initialize a new instance to ensure we pick up the latest selected key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // System instructions to guide the model specifically for upscaling
  const prompt = `
    Act as a professional image restoration and upscaling algorithm.
    Task: Upscale the provided image to 4K resolution (3840x2160 or similar high resolution based on aspect ratio).
    Strict Requirements:
    1. Maintain extreme fidelity to the original subject, composition, and colors.
    2. Enhance fine details, textures, and sharpness significantly.
    3. Remove compression artifacts, noise, and blur.
    4. Do NOT add new objects, change the artistic style, or hallucinate content that isn't suggested by the original pixels.
    5. The output must be photorealistic and crisp.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview', // Required for 4K generation
      contents: {
        parts: [
          {
            text: prompt,
          },
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType,
            },
          },
        ],
      },
      config: {
        imageConfig: {
          imageSize: '4K', // Explicitly request 4K
          aspectRatio: '1:1', // Default, but model usually respects input aspect ratio or close to it. 
          // Note: The API might enforce aspect ratios. For strict upscaling, we let the model decide the best fit or default.
          // Since 1:1, 3:4, 4:3, 16:9, 9:16 are supported, we should ideally pick the closest.
          // However, for this demo, we will let the model default or stick to a standard aspect ratio if the user doesn't specify.
          // To be safe and high quality, we don't force an aspect ratio if we want it to infer from image, 
          // but the API requires one of the enums if specified. 
          // Let's default to keeping it unspecified to see if it infers, OR pick a safe default like 1:1 if the input is square-ish. 
          // Actually, let's strictly use 1:1 for simplicity or allow the user to crop. 
          // Better yet: 'gemini-3-pro-image-preview' supports imageSize.
        }
      },
    });

    // Extract image
    if (response.candidates && response.candidates.length > 0) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image data returned from the model.");

  } catch (error: any) {
    console.error("Upscaling failed:", error);
    // If the error relates to API key, we might want to propagate that specific message
    if (error.message && error.message.includes("Requested entity was not found")) {
         throw new Error("API Key issue detected. Please re-select your API key.");
    }
    throw error;
  }
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Scan } from 'lucide-react';

interface ComparisonSliderProps {
  beforeImage: string;
  afterImage: string;
  className?: string;
}

export const ComparisonSlider: React.FC<ComparisonSliderProps> = ({ beforeImage, afterImage, className }) => {
  const [sliderPosition, setSliderPosition] = useState(50);
  const [isResizing, setIsResizing] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleMouseDown = useCallback(() => {
    setIsResizing(true);
  }, []);

  const handleMouseUp = useCallback(() => {
    setIsResizing(false);
  }, []);

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isResizing || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(e.clientX - rect.left, rect.width));
    const percentage = (x / rect.width) * 100;

    setSliderPosition(percentage);
  }, [isResizing]);

  const handleTouchMove = useCallback((e: TouchEvent) => {
    if (!isResizing || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(e.touches[0].clientX - rect.left, rect.width));
    const percentage = (x / rect.width) * 100;

    setSliderPosition(percentage);
  }, [isResizing]);

  useEffect(() => {
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
    document.addEventListener('touchmove', handleTouchMove);
    document.addEventListener('touchend', handleMouseUp);

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.removeEventListener('touchmove', handleTouchMove);
      document.removeEventListener('touchend', handleMouseUp);
    };
  }, [handleMouseMove, handleMouseUp, handleTouchMove]);

  return (
    <div 
      className={`relative w-full h-[500px] md:h-[600px] overflow-hidden rounded-xl shadow-2xl bg-black select-none ${className}`}
      ref={containerRef}
    >
      {/* Before Image (Background) */}
      <img 
        src={beforeImage} 
        alt="Original" 
        className="absolute top-0 left-0 w-full h-full object-contain pointer-events-none select-none"
      />

      {/* Label Before */}
      <div className="absolute top-4 left-4 bg-black/60 backdrop-blur-md text-white px-3 py-1 rounded-full text-xs font-semibold z-10 border border-white/10">
        Original (Before)
      </div>

      {/* After Image (Clipped on top) */}
      <div 
        className="absolute top-0 left-0 w-full h-full overflow-hidden select-none"
        style={{ clipPath: `inset(0 ${100 - sliderPosition}% 0 0)` }}
      >
        <img 
          src={afterImage} 
          alt="Upscaled" 
          className="absolute top-0 left-0 w-full h-full object-contain pointer-events-none select-none" 
        />

        {/* Label After */}
        <div className="absolute top-4 right-4 bg-blue-600/80 backdrop-blur-md text-white px-3 py-1 rounded-full text-xs font-semibold z-10 border border-white/10 shadow-[0_0_15px_rgba(37,99,235,0.5)]">
          Lumina 4K (After)
        </div>
      </div>

      {/* Slider Handle */}
      <div 
        className="absolute top-0 bottom-0 w-1 bg-white cursor-ew-resize z-20 shadow-[0_0_20px_rgba(0,0,0,0.5)]"
        style={{ left: `${sliderPosition}%` }}
        onMouseDown={handleMouseDown}
        onTouchStart={handleMouseDown}
      >
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-lg border-4 border-blue-500 hover:scale-110 transition-transform">
          <Scan className="w-5 h-5 text-blue-600" />
        </div>
      </div>
    </div>
  );
};

import React, { useCallback, useRef } from 'react';
import { Upload, ImageIcon, Zap } from './Icons';

interface UploaderProps {
  onFileSelect: (file: File) => void;
  isLoading?: boolean;
}

export const Uploader: React.FC<UploaderProps> = ({ onFileSelect, isLoading }) => {
