import React, { useState, useEffect } from 'react';
import { 
  Zap, 
  ArrowRight, 
  Download, 
  AlertCircle, 
  Loader2, 
  Maximize2,
  CheckCircle2
} from './components/Icons';
import { Uploader } from './components/Uploader';
import { ComparisonSlider } from './components/ComparisonSlider';
import { checkApiKey, promptForApiKey, upscaleImage } from './services/geminiService';
import { AppStatus, ImageData } from './types';

// Utility to convert file to base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      if (typeof reader.result === 'string') {
        // Remove data URL prefix (e.g., "data:image/jpeg;base64,")
        const base64 = reader.result.split(',')[1];
        resolve(base64);
      }
    };
    reader.onerror = error => reject(error);
  });
};

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [originalImage, setOriginalImage] = useState<ImageData | null>(null);
  const [processedImage, setProcessedImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [hasKey, setHasKey] = useState<boolean>(false);

  useEffect(() => {
    const initKey = async () => {
      try {
        const has = await checkApiKey();
        setHasKey(has);
      } catch (e) {
        console.error("Failed to check API key status", e);
      }
    };
    initKey();
  }, []);

  const handleApiKeySelection = async () => {
    try {
      setError(null);
      await promptForApiKey();
      const has = await checkApiKey();
      setHasKey(has);
    } catch (e: any) {
      setError(e.message || "Failed to select API key");
    }
  };

  const handleFileSelect = async (file: File) => {
    try {
      setError(null);
      setStatus(AppStatus.SELECTING_IMAGE);

      const objectUrl = URL.createObjectURL(file);
      const base64 = await fileToBase64(file);

      setOriginalImage({
        url: objectUrl,
        base64: base64,
        mimeType: file.type
      });

      setStatus(AppStatus.READY_TO_UPSCALE);
    } catch (e: any) {
      setError("Failed to process local file");
      setStatus(AppStatus.ERROR);
    }
  };

  const handleUpscale = async () => {
    if (!originalImage || !hasKey) return;

    try {
      setStatus(AppStatus.PROCESSING);
      setError(null);

      const resultDataUrl = await upscaleImage(originalImage.base64, originalImage.mimeType);

      setProcessedImage(resultDataUrl);
      setStatus(AppStatus.SUCCESS);
    } catch (e: any) {
      console.error(e);
      setError(e.message || "Upscaling failed. Please try again.");
      setStatus(AppStatus.ERROR);

      // If error is about API key, reset key state
      if (e.message && e.message.includes("API Key")) {
        setHasKey(false);
      }
    }
  };

  const reset = () => {
    setStatus(AppStatus.IDLE);
    setOriginalImage(null);
    setProcessedImage(null);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-[#020617] text-gray-100 overflow-x-hidden selection:bg-blue-500/30">
      {/* Header */}
      <header className="fixed top-0 left-0 right-0 z-50 bg-[#020617]/80 backdrop-blur-md border-b border-white/5">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={reset}>
            <div className="w-8 h-8 rounded-lg bg-gradient-to-tr from-blue-600 to-indigo-600 flex items-center justify-center shadow-lg shadow-blue-500/20">
              <Maximize2 className="w-5 h-5 text-white" />
            </div>
            <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-gray-400">
              Lumina
            </span>
            <span className="text-xs px-2 py-0.5 rounded-full bg-blue-500/10 text-blue-400 border border-blue-500/20 font-medium">
              4K AI
            </span>
          </div>

          <div className="flex items-center gap-4">
             {!hasKey ? (
               <button 
                onClick={handleApiKeySelection}
                className="text-sm bg-gray-800 hover:bg-gray-700 text-white px-4 py-2 rounded-full border border-gray-700 transition-all flex items-center gap-2"
               >
                 <span>Set API Key</span>
               </button>
             ) : (
               <div className="hidden sm:flex items-center gap-2 text-xs text-green-400 bg-green-900/20 px-3 py-1.5 rounded-full border border-green-900/30">
                 <CheckCircle2 className="w-3 h-3" />
                 <span>Gemini Pro Connected</span>
               </div>
             )}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="pt-24 pb-12 px-4 max-w-7xl mx-auto">

        {/* Intro Hero - Only show when IDLE */}
        {status === AppStatus.IDLE && (
          <div className="text-center mb-16 space-y-6 animate-fade-in-up">
            <h1 className="text-5xl md:text-7xl font-bold tracking-tight text-white mb-6">
              Upscale to <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 via-indigo-400 to-purple-400">4K Reality</span>
            </h1>
            <p className="text-lg text-gray-400 max-w-2xl mx-auto leading-relaxed">
              Transform low-resolution images into ultra-detailed 4K masterpieces using Google's Gemini 3 Pro Vision model. 
              Restore details, sharpen edges, and eliminate noise instantly.
            </p>

            {!hasKey && (
              <div className="max-w-md mx-auto mt-8 p-4 bg-yellow-500/10 border border-yellow-500/20 rounded-xl flex gap-3 text-left">
                <AlertCircle className="w-5 h-5 text-yellow-500 shrink-0 mt-0.5" />
                <div className="space-y-2">
                  <p className="text-sm text-yellow-200 font-medium">API Key Required</p>
                  <p className="text-xs text-yellow-500/80">
                    This tool requires the paid Gemini 3 Pro model for 4K generation. 
                    <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="underline hover:text-yellow-400 ml-1">
                       Billing info
                    </a>
                  </p>
                  <button 
                    onClick={handleApiKeySelection}
                    className="text-xs bg-yellow-500/20 hover:bg-yellow-500/30 text-yellow-200 px-3 py-1.5 rounded-lg transition-colors font-medium"
                  >
                    Select API Key
                  </button>
                </div>
              </div>
            )}
          </div>
        )}

        {/* Action Area */}
        <div className="space-y-8">

          {/* Uploader Section */}
          {status === AppStatus.IDLE && (
             <div className={`${!hasKey ? 'opacity-50 pointer-events-none grayscale' : ''} transition-all duration-500`}>
                <Uploader onFileSelect={handleFileSelect} isLoading={false} />
             </div>
          )}

          {/* Preview & Processing Section */}
          {(status === AppStatus.READY_TO_UPSCALE || status === AppStatus.PROCESSING) && originalImage && (
            <div className="max-w-4xl mx-auto space-y-8 animate-fade-in">
              <div className="bg-gray-900/40 rounded-3xl p-8 border border-white/5 shadow-2xl relative overflow-hidden">
                <div className="flex flex-col md:flex-row items-center gap-8">
                  <div className="relative w-full md:w-1/2 aspect-square rounded-2xl overflow-hidden bg-black/50 border border-gray-800">
                    <img src={originalImage.url} alt="Preview" className="w-full h-full object-contain" />
                    <div className="absolute bottom-4 left-4 bg-black/70 backdrop-blur text-xs font-mono px-2 py-1 rounded border border-white/10 text-gray-300">
                      Original Input
                    </div>
                  </div>

                  <div className="flex-1 space-y-6 text-center md:text-left">
                    <div>
                      <h3 className="text-2xl font-semibold text-white mb-2">Ready to Enhance</h3>
                      <p className="text-gray-400 text-sm">
                        We will upscale this image to 4K resolution using the <span className="text-blue-400">Gemini 3 Pro</span> vision model.
                        This process typically takes 10-20 seconds.
                      </p>
                    </div>

                    {status === AppStatus.READY_TO_UPSCALE ? (
                      <div className="flex flex-col sm:flex-row gap-4 justify-center md:justify-start">
                        <button 
                          onClick={handleUpscale}
                          className="flex items-center justify-center gap-2 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white px-8 py-4 rounded-xl font-semibold shadow-lg shadow-blue-600/20 transition-all hover:scale-[1.02]"
                        >
                          <Zap className="w-5 h-5" />
                          <span>Upscale to 4K</span>
                        </button>
                        <button 
                          onClick={reset}
                          className="px-6 py-4 rounded-xl text-gray-400 hover:text-white hover:bg-white/5 transition-colors font-medium"
                        >
                          Cancel
                        </button>
                      </div>
                    ) : (
                      <div className="space-y-4">
                        <div className="flex items-center gap-3 text-blue-400 justify-center md:justify-start animate-pulse">
                          <Loader2 className="w-5 h-5 animate-spin" />
                          <span className="font-medium">Enhancing details and resolution...</span>
                        </div>
                        <div className="h-1.5 w-full bg-gray-800 rounded-full overflow-hidden">
                          <div className="h-full bg-blue-500 w-1/2 animate-[shimmer_1.5s_infinite] bg-[linear-gradient(90deg,transparent,rgba(255,255,255,0.5),transparent)]"></div>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Success / Comparison View */}
          {status === AppStatus.SUCCESS && originalImage && processedImage && (
            <div className="space-y-8 animate-fade-in">
              <div className="flex items-center justify-between">
                <h2 className="text-2xl font-semibold text-white flex items-center gap-2">
                  <CheckCircle2 className="w-6 h-6 text-green-500" />
                  Restoration Complete
                </h2>
                <div className="flex gap-3">
                   <button 
                    onClick={reset}
                    className="text-sm text-gray-400 hover:text-white px-4 py-2 hover:bg-white/5 rounded-lg transition-colors"
                  >
                    Start New
                  </button>
                  <a 
                    href={processedImage} 
                    download="lumina-upscaled-4k.png"
                    className="flex items-center gap-2 bg-white text-black hover:bg-gray-200 px-5 py-2.5 rounded-lg font-medium transition-colors"
                  >
                    <Download className="w-4 h-4" />
                    Download 4K
                  </a>
                </div>
              </div>

              <ComparisonSlider beforeImage={originalImage.url} afterImage={processedImage} />

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                 <div className="bg-gray-900/50 p-6 rounded-xl border border-white/5">
                    <div className="text-gray-400 text-sm mb-1">Resolution</div>
                    <div className="text-xl font-semibold text-white">4K Ultra HD</div>
                 </div>
                 <div className="bg-gray-900/50 p-6 rounded-xl border border-white/5">
                    <div className="text-gray-400 text-sm mb-1">Details</div>
                    <div className="text-xl font-semibold text-white">Enhanced</div>
                 </div>
                 <div className="bg-gray-900/50 p-6 rounded-xl border border-white/5">
                    <div className="text-gray-400 text-sm mb-1">AI Model</div>
                    <div className="text-xl font-semibold text-blue-400">Gemini 3 Pro</div>
                 </div>
              </div>
            </div>
          )}

          {/* Error State */}
          {status === AppStatus.ERROR && (
            <div className="max-w-md mx-auto text-center space-y-6 mt-12 animate-fade-in">
              <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border border-red-500/20">
                <AlertCircle className="w-8 h-8 text-red-500" />
              </div>
              <div>
                <h3 className="text-xl font-semibold text-white mb-2">Processing Failed</h3>
                <p className="text-gray-400">{error || "Something went wrong during the upscaling process."}</p>
              </div>
              <button 
                onClick={reset}
                className="bg-gray-800 hover:bg-gray-700 text-white px-6 py-2.5 rounded-lg transition-colors border border-gray-700"
              >
                Try Again
              </button>
            </div>
          )}

        </div>
      </main>

      {/* Footer */}
      <footer className="fixed bottom-0 left-0 right-0 py-6 text-center text-gray-600 text-sm pointer-events-none">
        <p>Powered by Google Gemini 3 Pro Vision</p>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

export const checkApiKey = async (): Promise<boolean> => {
  // Use type assertion to avoid conflict with global AIStudio type
  const win = window as any;
  if (win.aistudio && win.aistudio.hasSelectedApiKey) {
    return await win.aistudio.hasSelectedApiKey();
  }
  return false;
};

export const promptForApiKey = async (): Promise<void> => {
  const win = window as any;
  if (win.aistudio && win.aistudio.openSelectKey) {
    await win.aistudio.openSelectKey();
  } else {
    console.error("AI Studio environment not detected.");
    throw new Error("AI Studio environment not supported. Please run this app in the Project IDX or AI Studio environment.");
  }
};

export const upscaleImage = async (
  base64Data: string,
  mimeType: string
): Promise<string> => {
  // Always initialize a new instance to ensure we pick up the latest selected key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // System instructions to guide the model specifically for upscaling
  const prompt = `
    Act as a professional image restoration and upscaling algorithm.
    Task: Upscale the provided image to 4K resolution (3840x2160 or similar high resolution based on aspect ratio).
    Strict Requirements:
    1. Maintain extreme fidelity to the original subject, composition, and colors.
    2. Enhance fine details, textures, and sharpness significantly.
    3. Remove compression artifacts, noise, and blur.
    4. Do NOT add new objects, change the artistic style, or hallucinate content that isn't suggested by the original pixels.
    5. The output must be photorealistic and crisp.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview', // Required for 4K generation
      contents: {
        parts: [
          {
            text: prompt,
          },
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType,
            },
          },
        ],
      },
      config: {
        imageConfig: {
          imageSize: '4K', // Explicitly request 4K
          aspectRatio: '1:1', // Default, but model usually respects input aspect ratio or close to it. 
          // Note: The API might enforce aspect ratios. For strict upscaling, we let the model decide the best fit or default.
          // Since 1:1, 3:4, 4:3, 16:9, 9:16 are supported, we should ideally pick the closest.
          // However, for this demo, we will let the model default or stick to a standard aspect ratio if the user doesn't specify.
          // To be safe and high quality, we don't force an aspect ratio if we want it to infer from image, 
          // but the API requires one of the enums if specified. 
          // Let's default to keeping it unspecified to see if it infers, OR pick a safe default like 1:1 if the input is square-ish. 
          // Actually, let's strictly use 1:1 for simplicity or allow the user to crop. 
          // Better yet: 'gemini-3-pro-image-preview' supports imageSize.
        }
      },
    });

    // Extract image
    if (response.candidates && response.candidates.length > 0) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image data returned from the model.");

  } catch (error: any) {
    console.error("Upscaling failed:", error);
    // If the error relates to API key, we might want to propagate that specific message
    if (error.message && error.message.includes("Requested entity was not found")) {
         throw new Error("API Key issue detected. Please re-select your API key.");
    }
    throw error;
  }
};

