import { GoogleGenAI } from "@google/genai";
import { UpscaleMode } from "../types";

// Helper to determine the closest supported aspect ratio
const getClosestAspectRatio = (width: number, height: number): string => {
  const targetRatio = width / height;
  const supportedRatios: Record<string, number> = {
    '1:1': 1,
    '3:4': 0.75,
    '4:3': 1.333333,
    '9:16': 0.5625,
    '16:9': 1.777778
  };

  return Object.keys(supportedRatios).reduce((prev, curr) => {
    return (Math.abs(supportedRatios[curr] - targetRatio) < Math.abs(supportedRatios[prev] - targetRatio) ? curr : prev);
  });
};

export const upscaleImage = async (
  base64Data: string,
  mimeType: string,
  width: number,
  height: number,
  mode: UpscaleMode = 'standard',
  removeBackground: boolean = false
): Promise<string> => {
  // Use the standard environment variable for the API key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Calculate best aspect ratio
  const aspectRatio = getClosestAspectRatio(width, height);

  // Customize prompt based on mode
  let taskDescription = mode === '2x'
    ? "Perform a 2x Super Resolution upscale. Drastically increase pixel density and resolve fine details to support double the resolution. Focus on sharp edges and realistic texture synthesis."
    : "Re-generate the provided image with significantly improved resolution, clarity, and detail.";

  if (removeBackground) {
    taskDescription += " CRITICAL: You must also strictly remove the background. Isolate the main subject completely and place it on a clean, pure white background (hex #FFFFFF). Ensure hair/edges are perfectly masked.";
  }

  // System instructions to guide the model specifically for upscaling
  const prompt = `
    Act as a professional image restoration and upscaling AI.
    Task: ${taskDescription}
    Strict Requirements:
    1. Maintain extreme fidelity to the original subject, composition, and colors.
    2. Maximize sharpness and texture details.
    3. Remove compression artifacts, noise, and blur.
    4. Do NOT add new objects or change the artistic style (unless removing background as requested).
    5. Output the highest resolution possible.
    ${removeBackground ? '6. Isolate the subject. BACKGROUND MUST BE PURE WHITE.' : ''}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Switched to the free-tier friendly model
      contents: {
        parts: [
          {
            text: prompt,
          },
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType,
            },
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio, 
          // imageSize: '4K' is NOT supported in gemini-2.5-flash-image, so it is removed.
        }
      },
    });

    // Extract image
    if (response.candidates && response.candidates.length > 0) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image data returned from the model.");

  } catch (error: any) {
    console.error("Upscaling failed:", error);
    throw error;
  }
};

