              <ComparisonSlider beforeImage={originalImage.url} afterImage={processedImage} />

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                 <div className="bg-gray-900/50 p-6 rounded-xl border border-white/5">
                    <div className="text-gray-400 text-sm mb-1">Mode</div>
                    <div className="text-xl font-semibold text-white">
                      {upscaleMode === '2x' ? '2x Super Res' : 'Standard Enhance'}
                    </div>
                 </div>
                 <div className="bg-gray-900/50 p-6 rounded-xl border border-white/5">
                    <div className="text-gray-400 text-sm mb-1">Background</div>
                    <div className="text-xl font-semibold text-white">
                       {removeBackground ? 'Removed (White)' : 'Preserved'}
                    </div>
                 </div>
                 <div className="bg-gray-900/50 p-6 rounded-xl border border-white/5">
                    <div className="text-gray-400 text-sm mb-1">AI Model</div>
                    <div className="text-xl font-semibold text-blue-400">Gemini 2.5 Flash</div>
                 </div>
              </div>
            </div>
          )}

          {/* Error State */}
          {status === AppStatus.ERROR && (
            <div className="max-w-md mx-auto text-center space-y-6 mt-12 animate-fade-in">
              <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border border-red-500/20">
                <AlertCircle className="w-8 h-8 text-red-500" />
              </div>
              <div>
                <h3 className="text-xl font-semibold text-white mb-2">Processing Failed</h3>
                <p className="text-gray-400">{error || "Something went wrong during the upscaling process."}</p>
              </div>
              <button 
                onClick={reset}
                className="bg-gray-800 hover:bg-gray-700 text-white px-6 py-2.5 rounded-lg transition-colors border border-gray-700"
              >
                Try Again
              </button>
            </div>
          )}

        </div>
      </main>

      {/* Footer */}
      <footer className="fixed bottom-0 left-0 right-0 py-6 text-center text-gray-600 text-sm pointer-events-none">
        <p>Powered by Google Gemini 2.5 Flash</p>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { UpscaleMode } from "../types";

// Helper to determine the closest supported aspect ratio
const getClosestAspectRatio = (width: number, height: number): string => {
  const targetRatio = width / height;
  const supportedRatios: Record<string, number> = {
    '1:1': 1,
    '3:4': 0.75,
    '4:3': 1.333333,
    '9:16': 0.5625,
    '16:9': 1.777778
  };

  return Object.keys(supportedRatios).reduce((prev, curr) => {
    return (Math.abs(supportedRatios[curr] - targetRatio) < Math.abs(supportedRatios[prev] - targetRatio) ? curr : prev);
  });
};

export const upscaleImage = async (
  base64Data: string,
  mimeType: string,
  width: number,
  height: number,
  mode: UpscaleMode = 'standard',
  removeBackground: boolean = false
): Promise<string> => {
  // Use the standard environment variable for the API key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Calculate best aspect ratio
  const aspectRatio = getClosestAspectRatio(width, height);

  // Customize prompt based on mode
  let taskDescription = mode === '2x'
    ? "Upscale this image 2x. Increase pixel density, resolution and details. Focus on sharp edges and realistic textures."
    : "Enhance this image. Improve resolution, clarity, and detail significantly.";

  if (removeBackground) {
    taskDescription += " Also, remove the background and replace it with a solid white background.";
  }

  // Simplified prompt to ensure model understands it is an image generation task
  const prompt = `${taskDescription}
    Requirements:
    - High fidelity to original.
    - Remove artifacts/noise.
    - Do not change content unless removing background.
    - Output pure image.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          // IMPORTANT: Image part must come before text for editing tasks to work reliably
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType,
            },
          },
          {
            text: prompt,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio, 
        }
      },
    });

    let textResponse = '';

    // Extract image
    if (response.candidates && response.candidates.length > 0) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          const mime = part.inlineData.mimeType || 'image/png';
          return `data:${mime};base64,${part.inlineData.data}`;
        }
        if (part.text) {
          textResponse += part.text;
        }
      }
    }

    // If text was returned but no image, treat it as a refusal/error
    if (textResponse) {
      console.warn("Model returned text instead of image:", textResponse);
      throw new Error(`AI Request Failed: ${textResponse.slice(0, 150)}...`);
    }

    throw new Error("No image data returned from the model.");

  } catch (error: any) {
    console.error("Upscaling failed:", error);
    throw error;
  }
};
